---
import '../styles/global.css';

interface Props {
  title?: string;
  description?: string;
}

const {
  title = 'incomplete.fun',
  description = 'A collection of fun, incomplete things.',
} = Astro.props;
---

<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <link rel="icon" type="image/svg+xml" href="/favicon.svg" />
    <link rel="icon" href="/favicon.ico" />
    <meta name="viewport" content="width=device-width" />
    <meta name="description" content={description} />
    <title>{title}</title>
  </head>
  <body>
    <slot />
  </body>
</html>

---
import BaseLayout from './BaseLayout.astro';

interface Props {
  name: string;
  back?: boolean;
}

const { name, back = false } = Astro.props;
const title = name === 'incomplete.fun' ? name : `${name} - incomplete.fun`;
---

<BaseLayout title={title}>
  <div class="app-shell">
    <div class="topbar">
      {back && <a class="back-link" href="/" aria-label="Back to home">←</a>}
      <span><strong>{name}</strong></span>
    </div>
    <main class="page">
      <slot />
    </main>
  </div>
</BaseLayout>

:root {
  color-scheme: light dark;
  --bg: #fbfbf9;
  --fg: #181817;
  --muted: #77736b;
  --line: #dedbd2;
  --accent: currentColor;
  --border: var(--line);
  --mono: inherit;
  --space: clamp(1rem, 4vw, 2.5rem);
  --measure: 38rem;
  font-family: ui-monospace, "SFMono-Regular", Menlo, Consolas, monospace;
}

@media (prefers-color-scheme: dark) {
  :root {
    --bg: #10100f;
    --fg: #eeeeea;
    --muted: #98948b;
    --line: #2d2b28;
  }
}

* { box-sizing: border-box; }

body {
  margin: 0;
  background: var(--bg);
  color: var(--fg);
  font-size: 15px;
  line-height: 1.65;
}

a {
  color: inherit;
  text-decoration: underline;
  text-decoration-color: var(--line);
  text-underline-offset: .25em;
}

a:hover { text-decoration-color: currentColor; }

h1, h2, h3, p, ul, ol { margin: 0 0 1rem; }

h1, h2, h3, strong { font-weight: 600; }

ul, ol { padding-left: 1.25rem; }

code {
  padding: .1em .3em;
  border: 1px solid var(--line);
  border-radius: 3px;
}

.app-shell, .canvas-app {
  min-height: 100dvh;
  background: var(--bg);
}

.app-shell { display: grid; grid-template-rows: auto 1fr; }
.canvas-app { display: flex; flex-direction: column; }

.topbar {
  display: flex;
  align-items: center;
  gap: 1rem;
  min-height: 3.25rem;
  padding: .75rem var(--space);
  border-bottom: 1px solid var(--line);
  flex-wrap: wrap;
}

.back-link {
  color: var(--muted);
  text-decoration: none;
}

.page {
  width: min(100%, var(--measure));
  margin: 0 auto;
  padding: calc(var(--space) * 1.4) var(--space);
}

.home-intro { color: var(--muted); }

.home-links {
  list-style: none;
  padding: 0;
}

.home-links a {
  display: inline-block;
  padding: .15rem 0;
}

.canvas-stage {
  position: relative;
  flex: 1;
  overflow: hidden;
}

button, input {
  font: inherit;
  color: inherit;
}

.toolbar-button,
.metric-button {
  background: transparent;
  border: 1px solid var(--line);
  border-radius: 999px;
  padding: .15rem .7rem;
  cursor: pointer;
}

.toolbar-button:hover,
.metric-button:hover,
.metric-button.is-active {
  background: var(--fg);
  border-color: var(--fg);
  color: var(--bg);
}

.control-label {
  display: inline-flex;
  align-items: center;
  gap: .4rem;
  color: var(--muted);
}

input[type="number"] {
  width: 3.5rem;
  background: transparent;
  border: 1px solid var(--line);
  border-radius: 4px;
  padding: .1rem .35rem;
}

input[type="color"] {
  width: 2rem;
  height: 1.4rem;
  padding: 0;
  border: 1px solid var(--line);
  background: transparent;
}

input[type="checkbox"],
input[type="range"] {
  accent-color: var(--fg);
}

---
import BaseLayout from '../layouts/BaseLayout.astro';
---

<BaseLayout title="p-adic calculator - incomplete.fun">
  <main class="padic-page">
    <header class="padic-header">
      <a class="back-link" href="/" aria-label="Back to home">←</a>
      <div>
        <h1>p-adic calculator</h1>
        <p>Explore rational numbers by their base-p digits extending to the left.</p>
      </div>
    </header>

    <section class="padic-grid" id="padic-app">
      <form class="padic-card" id="padic-expansion-form">
        <h2>rational expansion</h2>
        <label>
          prime p
          <input id="padic-prime" type="number" min="2" max="97" step="1" value="5" />
        </label>
        <label>
          rational number
          <input id="padic-rational" type="text" value="1/3" inputmode="text" />
        </label>
        <label>
          digits
          <input id="padic-digits" type="number" min="1" max="40" step="1" value="16" />
        </label>
        <button class="toolbar-button" type="submit">compute</button>
        <div class="padic-output" id="padic-expansion-output" aria-live="polite"></div>
      </form>

      <form class="padic-card" id="padic-inverse-form">
        <h2>modular inverse</h2>
        <label>
          a
          <input id="padic-inverse-a" type="text" value="7" />
        </label>
        <label>
          modulus p^k
          <span class="padic-inline-inputs">
            <input id="padic-inverse-p" type="number" min="2" max="97" step="1" value="5" aria-label="prime p" />
            <input id="padic-inverse-k" type="number" min="1" max="30" step="1" value="6" aria-label="exponent k" />
          </span>
        </label>
        <button class="toolbar-button" type="submit">invert</button>
        <div class="padic-output" id="padic-inverse-output" aria-live="polite"></div>
      </form>

      <form class="padic-card padic-wide" id="padic-hensel-form">
        <h2>hensel lift</h2>
        <p class="padic-note">Enter polynomial coefficients low to high. Example: <code>-2,0,1</code> is x² − 2.</p>
        <label>
          coefficients
          <input id="padic-poly" type="text" value="-2,0,1" />
        </label>
        <label>
          root mod p
          <input id="padic-root" type="text" value="3" />
        </label>
        <label>
          lift to p^k
          <span class="padic-inline-inputs">
            <input id="padic-hensel-p" type="number" min="2" max="97" step="1" value="7" aria-label="prime p" />
            <input id="padic-hensel-k" type="number" min="1" max="30" step="1" value="8" aria-label="exponent k" />
          </span>
        </label>
        <button class="toolbar-button" type="submit">lift</button>
        <div class="padic-output" id="padic-hensel-output" aria-live="polite"></div>
      </form>
    </section>
  </main>
</BaseLayout>

<style>
  .padic-page {
    width: min(100%, 72rem);
    margin: 0 auto;
    padding: var(--space);
  }

  .padic-header {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
    margin-bottom: 1.5rem;
  }

  .padic-header h1 {
    margin-bottom: 0.25rem;
    font-size: clamp(1.4rem, 3vw, 2rem);
  }

  .padic-header p,
  .padic-note {
    color: var(--muted);
  }

  .padic-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(min(100%, 22rem), 1fr));
    gap: 1rem;
  }

  .padic-card {
    border: 1px solid var(--line);
    padding: 1rem;
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
  }

  .padic-wide {
    grid-column: 1 / -1;
  }

  .padic-card h2 {
    font-size: 1rem;
    margin-bottom: 0.25rem;
  }

  .padic-card label {
    display: grid;
    gap: 0.25rem;
    color: var(--muted);
  }

  .padic-card input {
    width: 100%;
    background: transparent;
    color: var(--fg);
    border: 1px solid var(--line);
    border-radius: 4px;
    padding: 0.35rem 0.45rem;
    font-family: var(--mono);
  }

  .padic-inline-inputs {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 0.5rem;
  }

  .padic-output {
    min-height: 7rem;
    border-top: 1px solid var(--line);
    padding-top: 0.75rem;
    overflow-x: auto;
  }
</style>

<style is:global>
  .padic-result {
    display: grid;
    gap: 0.6rem;
    font-variant-numeric: tabular-nums;
  }

  .padic-result code {
    white-space: nowrap;
  }

  .padic-error {
    color: #c33;
  }

  .padic-table {
    width: 100%;
    border-collapse: collapse;
    font-size: 0.85rem;
  }

  .padic-table th,
  .padic-table td {
    border-bottom: 1px solid var(--line);
    padding: 0.25rem 0.4rem;
    text-align: left;
    white-space: nowrap;
  }

  .padic-muted {
    color: var(--muted);
  }
</style>

<script>
  import '../scripts/padic.ts';
</script>

---
import BaseLayout from '../layouts/BaseLayout.astro';
---

<BaseLayout title="symmetry - incomplete.fun">
  <div class="canvas-app" id="symmetry-app">
    <div class="topbar" style="gap: 1.5rem;">
      <a class="back-link" href="/" aria-label="Back to home">←</a>
      <span><strong>symmetry</strong></span>

      <label class="control-label">
        n=
        <input id="symmetry-segments" type="number" min="1" max="36" value="6" />
      </label>

      <label class="control-label" style="cursor: pointer;">
        <input id="symmetry-mirror" type="checkbox" />
        mirror
      </label>

      <label class="control-label">
        color
        <input id="symmetry-color" type="color" value="#4d9fff" />
      </label>

      <label class="control-label">
        width
        <input id="symmetry-width" type="range" min="1" max="20" value="2" />
        <span id="symmetry-width-value" style="color: var(--muted); min-width: 1.5rem;">2</span>
      </label>

      <button class="toolbar-button" id="symmetry-clear" type="button">clear</button>
    </div>

    <div class="canvas-stage">
      <canvas id="symmetry-canvas" style="display: block; cursor: crosshair; touch-action: none;"></canvas>
    </div>
  </div>
</BaseLayout>

<style>
  #symmetry-segments {
    width: 3rem;
    background: var(--bg);
    color: var(--fg);
    border: 1px solid var(--border);
    font-family: var(--mono);
    font-size: 0.85rem;
    padding: 0.1rem 0.3rem;
  }

  #symmetry-mirror,
  #symmetry-width {
    accent-color: var(--accent);
  }

  #symmetry-color {
    width: 2rem;
    height: 1.4rem;
    border: 1px solid var(--border);
    padding: 0;
    background: none;
    cursor: pointer;
  }

  #symmetry-width {
    width: 5rem;
  }
</style>

<script>
  import '../scripts/symmetry.ts';
</script>

---
import BaseLayout from '../layouts/BaseLayout.astro';
---

<BaseLayout title="voronoi - incomplete.fun">
  <div class="canvas-app" id="voronoi-app">
    <div class="topbar" id="voronoi-toolbar">
      <a class="back-link" href="/" aria-label="Back to home">←</a>
      <span><strong>voronoi</strong></span>
      <span style="color: var(--border);">|</span>

      <button class="metric-button" type="button" data-metric="minkowski05" title="minkowski p=1/2 (star)">L½</button>
      <button class="metric-button" type="button" data-metric="manhattan" title="manhattan (diamond)">L1</button>
      <button class="metric-button" type="button" data-metric="euclidean" title="euclidean (circular)">L2</button>
      <button class="metric-button" type="button" data-metric="minkowski3" title="minkowski p=3 (rounded square)">L3</button>
      <button class="metric-button" type="button" data-metric="chebyshev" title="chebyshev (square)">L∞</button>

      <span id="voronoi-help" style="color: var(--muted); font-size: 0.75rem; margin-left: auto;">
        click to place · right-click removes
      </span>
      <button class="toolbar-button" id="voronoi-clear" type="button">clear</button>
    </div>

    <div id="voronoi-hover-row">
      <span id="voronoi-coords">(0, 0)</span>
      <div id="voronoi-distances"></div>
    </div>

    <div class="canvas-stage" id="voronoi-stage" style="cursor: crosshair; touch-action: none;">
      <canvas id="voronoi-gl" style="position: absolute; inset: 0; display: block;"></canvas>
      <canvas id="voronoi-markers" style="position: absolute; inset: 0; display: block; pointer-events: none;"></canvas>
      <div id="voronoi-webgl-error" role="status">
        WebGL2 is required for this experiment.
      </div>
      <div id="voronoi-empty">
        <span>click to place points</span>
        <span style="font-size: 0.75rem;">each point uses its own distance metric</span>
      </div>
    </div>
  </div>
</BaseLayout>

<style>
  .metric-button {
    background: none;
    border: 1px solid var(--border);
    color: var(--fg);
    font-family: var(--mono);
    font-size: 0.8rem;
    padding: 0.15rem 0.55rem;
    cursor: pointer;
    border-radius: 2px;
  }

  .metric-button.is-active {
    background: var(--accent);
    border-color: var(--accent);
    color: #fff;
  }

  #voronoi-hover-row {
    display: grid;
    grid-template-columns: 6.5rem minmax(0, 1fr);
    column-gap: 0.75rem;
    padding: 0 1rem;
    border-bottom: 1px solid var(--border);
    font-size: 0.78rem;
    font-family: var(--mono);
    line-height: 1.25;
    min-height: 1.9rem;
    max-height: 6.5rem;
    overflow-x: hidden;
    overflow-y: auto;
    font-variant-numeric: tabular-nums;
  }

  #voronoi-coords {
    color: var(--muted);
    white-space: nowrap;
    padding-top: 0.35rem;
    visibility: hidden;
  }

  #voronoi-distances {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(18rem, 1fr));
    gap: 0.25rem 0.75rem;
    min-width: 0;
    padding: 0.25rem 0;
  }

  #voronoi-webgl-error,
  #voronoi-empty {
    position: absolute;
    inset: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-direction: column;
    gap: 0.4rem;
    color: var(--muted);
    font-family: var(--mono);
    pointer-events: none;
  }

  #voronoi-webgl-error {
    display: none;
  }
</style>

<style is:global>
  /* Applied to elements created dynamically in voronoi.ts */
  .distance-entry {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    min-width: 0;
    color: var(--muted);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
  }

  .distance-entry.is-winner {
    color: var(--fg);
    font-weight: bold;
  }

  .distance-dot {
    display: inline-block;
    width: 7px;
    height: 7px;
    border-radius: 50%;
    flex-shrink: 0;
  }

  .distance-label {
    color: var(--muted);
    font-size: 0.72rem;
    flex-shrink: 0;
  }

  .distance-value {
    overflow: hidden;
    text-overflow: ellipsis;
  }
</style>

<script>
  import '../scripts/voronoi.ts';
</script>

---
import PageLayout from '../../layouts/PageLayout.astro';

function fib(n: number): bigint {
  let a = 0n, b = 1n;
  for (let i = 0; i < n; i++) [a, b] = [b, a + b];
  return a;
}

export function getStaticPaths() {
  return Array.from({ length: 101 }, (_, n) => ({ params: { n: String(n) } }));
}

const nParam = Astro.params.n ?? '';

if (!/^\d+$/.test(nParam)) {
  return new Response(null, { status: 404 });
}

const n = Number.parseInt(nParam, 10);
---

<PageLayout name="fibonacci" back>
  <p class="fib-result">fib({n}) = <strong>{fib(n).toString()}</strong></p>
</PageLayout>

<style>
  .fib-result {
    overflow-wrap: anywhere;
    word-break: break-word;
  }
</style>

